const canvas = document.getElementById("game");
const ctx = canvas.getContext("2d");

const W = 390;
const H = 720;
const BASE = { x: 165, y: 560 };
const PLATFORM_COUNT = 6;
const SAFE_LEFT = 76;
const SAFE_RIGHT = 76;
const SAFE_TOP = 118;

const startScreen = document.getElementById("startScreen");
const deadScreen = document.getElementById("deadScreen");
const scoreEl = document.getElementById("score");
const startBtn = document.getElementById("startBtn");
const reviveBtn = document.getElementById("reviveBtn");
const restartBtn = document.getElementById("restartBtn");

let gameState = "start";
let score = 0;
let power = 0;
let charging = false;
let platforms = [];
let currentPlatform = null;
let targetPlatform = null;
let player = null;
let jump = null;
let cameraShake = 0;
let flash = 0;
let routeDir = 1;
let routeStreak = 0;

let particles = [];
let rings = [];
let butterflies = [];
let slashes = [];
let afterImages = [];

const sprites = {};
const spriteNames = ["idle", "charge", "jump", "fall", "land"];
let spritesLoaded = 0;

// V8：手机/GitHub Pages 稳定版。
// 人物素材直接内嵌到 game.js，手机端不再因为 assets 文件夹漏传而导致人物消失。
const SPRITE_DATA = {
  idle: "data:image/png;base64,",
  charge: "data:image/png;base64,",
  jump: "data:image/png;base64,",
  fall: "data:image/png;base64,",
  land: "data:image/png;base64,"
};

const spriteConfig = {
  idle:   { h: 136, y: 0,  x: 0 },
  charge: { h: 136, y: 2,  x: 0 },
  jump:   { h: 148, y: 3,  x: 0 },
  fall:   { h: 138, y: 2,  x: 0 },
  land:   { h: 132, y: 1,  x: 0 }
};

spriteNames.forEach(name => {
  const img = new Image();
  img.onload = () => spritesLoaded++;
  img.onerror = () => {
    console.warn("角色素材加载失败，使用备用绘制：", name);
  };
  img.src = SPRITE_DATA[name];
  sprites[name] = img;
});

const motes = Array.from({ length: 44 }, () => ({
  x: Math.random() * W,
  y: Math.random() * H,
  r: Math.random() * 1.8 + 0.5,
  a: Math.random() * 0.22 + 0.06,
  speed: Math.random() * 0.22 + 0.05,
  drift: Math.random() * 0.35 + 0.06
}));

const bgButterflies = Array.from({ length: 12 }, () => ({
  x: Math.random() * W,
  y: Math.random() * H,
  s: Math.random() * 0.34 + 0.14,
  speed: Math.random() * 0.35 + 0.1,
  phase: Math.random() * Math.PI * 2,
  alpha: Math.random() * 0.24 + 0.12
}));


// 简易内置音效：不用 mp3 文件，直接用 Web Audio 合成。
// 浏览器要求用户点击后才能播放，所以第一次点击开始/蓄力时会自动解锁。
let audioCtx = null;
let audioEnabled = true;

function initAudio() {
  if (!audioEnabled) return;
  if (!audioCtx) {
    const AC = window.AudioContext || window.webkitAudioContext;
    if (!AC) {
      audioEnabled = false;
      return;
    }
    audioCtx = new AC();
  }
  if (audioCtx.state === "suspended") {
    audioCtx.resume();
  }
}

function playTone(freq, duration = 0.08, type = "sine", volume = 0.045, slideTo = null) {
  if (!audioEnabled) return;
  initAudio();
  if (!audioCtx) return;

  const now = audioCtx.currentTime;
  const osc = audioCtx.createOscillator();
  const gain = audioCtx.createGain();

  osc.type = type;
  osc.frequency.setValueAtTime(freq, now);
  if (slideTo) {
    osc.frequency.exponentialRampToValueAtTime(Math.max(20, slideTo), now + duration);
  }

  gain.gain.setValueAtTime(0.0001, now);
  gain.gain.exponentialRampToValueAtTime(volume, now + 0.012);
  gain.gain.exponentialRampToValueAtTime(0.0001, now + duration);

  osc.connect(gain);
  gain.connect(audioCtx.destination);
  osc.start(now);
  osc.stop(now + duration + 0.02);
}

function playSound(name) {
  if (!audioEnabled) return;

  if (name === "start") {
    playTone(520, 0.08, "sine", 0.035, 780);
    setTimeout(() => playTone(920, 0.07, "triangle", 0.025, 1180), 70);
  }

  if (name === "charge") {
    playTone(260, 0.06, "sine", 0.018, 360);
  }

  if (name === "jump") {
    playTone(420, 0.10, "triangle", 0.042, 880);
    setTimeout(() => playTone(980, 0.06, "sine", 0.018, 1380), 40);
  }

  if (name === "land") {
    playTone(220, 0.10, "sine", 0.045, 120);
    setTimeout(() => playTone(520, 0.05, "triangle", 0.022, 420), 35);
  }

  if (name === "fall") {
    playTone(260, 0.18, "sawtooth", 0.032, 80);
  }

  if (name === "revive") {
    playTone(360, 0.10, "sine", 0.035, 720);
    setTimeout(() => playTone(720, 0.10, "triangle", 0.03, 1080), 85);
    setTimeout(() => playTone(1080, 0.12, "sine", 0.026, 1440), 165);
  }
}

function setupCanvas() {
  const dpr = window.devicePixelRatio || 1;
  canvas.width = W * dpr;
  canvas.height = H * dpr;

  // 关键修复：不要再写死 390px，否则手机/预览窗口宽度变化时，
  // canvas 右侧会露出素材边或页面底色。
  canvas.style.width = "100%";
  canvas.style.height = "100%";

  ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
  ctx.imageSmoothingEnabled = true;
}

function hide(el) { if (el) el.classList.add("hidden"); }
function show(el) { if (el) el.classList.remove("hidden"); }
function updateScore() { scoreEl.textContent = score; }
function random(min, max) { return Math.random() * (max - min) + min; }
function clamp(v, min, max) { return Math.max(min, Math.min(max, v)); }
function lerp(a, b, t) { return a + (b - a) * t; }
function ease(t) { return t < 0.5 ? 2 * t * t : 1 - Math.pow(-2 * t + 2, 2) / 2; }


// V8 手机端防误触：禁止长按菜单、选中文字、双指/拖动导致页面行为。
document.addEventListener("contextmenu", e => e.preventDefault());
document.addEventListener("selectstart", e => e.preventDefault());
document.addEventListener("dragstart", e => e.preventDefault());
document.addEventListener("gesturestart", e => e.preventDefault());

function difficulty() {
  return clamp(score / 28, 0, 1);
}

function difficultyLabel() {
  if (score < 6) return "初级";
  if (score < 14) return "进阶";
  if (score < 24) return "困难";
  return "极限";
}

function startGame() {
  initAudio();
  playSound("start");
  gameState = "playing";
  score = 0;
  power = 0;
  charging = false;
  jump = null;
  particles = [];
  rings = [];
  butterflies = [];
  slashes = [];
  afterImages = [];
  cameraShake = 0;
  flash = 0;
  routeDir = Math.random() > 0.5 ? 1 : -1;
  routeStreak = 0;

  hide(startScreen);
  hide(deadScreen);

  platforms = [makePlatform(BASE.x, BASE.y, 74, 32, "main")];
  while (platforms.length < PLATFORM_COUNT) addPlatform();

  currentPlatform = platforms[0];
  targetPlatform = platforms[1];

  player = {
    x: currentPlatform.x,
    y: currentPlatform.y - 8,
    state: "idle",
    prevState: "idle",
    frameT: 0,
    scaleX: 1,
    scaleY: 1,
    dir: 1,
    angle: 0,
    shadow: 1,
    landTimer: 0,
    offsetXOnPlatform: 0,
    vy: 0
  };

  faceNextPlatform();
  updateScore();
}

function restart() { startGame(); }

function revive() {
  initAudio();
  playSound("revive");
  hide(deadScreen);
  gameState = "playing";
  charging = false;
  power = 0;
  jump = null;
  if (player && currentPlatform) {
    player.x = currentPlatform.x + (player.offsetXOnPlatform || 0);
    player.y = currentPlatform.y - 8;
    player.state = "idle";
    player.prevState = "idle";
    player.frameT = 0;
    player.scaleX = 1;
    player.scaleY = 1;
    player.angle = 0;
    player.shadow = 1;
    player.vy = 0;
    faceNextPlatform();
  }
  cameraShake = 5;
  flash = 0.1;
  spawnRing(player.x, currentPlatform.y + 6, 24, 8, "rgba(255,220,255,.85)", 2.8, 0.025, 8);
  spawnRing(player.x, currentPlatform.y + 6, 42, 14, "rgba(190,145,255,.58)", 2.2, 0.022, 10);
  for (let i = 0; i < 28; i++) spawnButterfly(player.x, player.y - 52, random(-2.2, 2.2), random(-1.8, 1.4), random(0.22, 0.42));
}

function makePlatform(x, y, rx, ry, type) {
  return { x, y, rx, ry, h: 56, type, press: 0, seed: Math.random() * 9, pulse: Math.random() * 9, glow: Math.random() > 0.35 };
}

function chooseStyle() {
  const r = Math.random();

  // V5：难度会随着分数逐渐提升。
  // 前期多给 normal / near / calm，后期增加 long / mini，减少安全平台。
  if (score < 5) {
    if (r < 0.38) return "normal";
    if (r < 0.66) return "near";
    if (r < 0.82) return "calm";
    if (r < 0.94) return "long";
    return "mini";
  }

  if (score < 12) {
    if (r < 0.32) return "normal";
    if (r < 0.54) return "near";
    if (r < 0.68) return "calm";
    if (r < 0.88) return "long";
    return "mini";
  }

  if (score < 22) {
    if (r < 0.24) return "normal";
    if (r < 0.42) return "near";
    if (r < 0.52) return "calm";
    if (r < 0.78) return "long";
    return "mini";
  }

  if (r < 0.18) return "normal";
  if (r < 0.32) return "near";
  if (r < 0.40) return "calm";
  if (r < 0.70) return "long";
  return "mini";
}

function chooseDir(last, style) {
  let dir = routeDir;
  if (last.x < SAFE_LEFT + 42) {
    dir = 1; routeStreak = 0;
  } else if (last.x > W - SAFE_RIGHT - 42) {
    dir = -1; routeStreak = 0;
  } else {
    if (routeStreak >= (score < 8 ? 2 : 3)) dir = -routeDir;
    else {
      let keep = 0.44;
      if (style === "calm") keep = 0.62;
      if (style === "near") keep = 0.54;
      if (style === "long") keep = 0.38;
      dir = Math.random() < keep ? routeDir : -routeDir;
    }
  }
  return dir;
}

function rangeByStyle(style) {
  const d = difficulty();

  // V5：距离随难度平滑增加，但不会一下变变态。
  if (style === "near") {
    return {
      dx1: 82 + d * 10,
      dx2: 108 + d * 16,
      dy1: 52 + d * 8,
      dy2: 68 + d * 10
    };
  }

  if (style === "long") {
    return {
      dx1: 116 + d * 18,
      dx2: 148 + d * 24,
      dy1: 58 + d * 10,
      dy2: 78 + d * 14
    };
  }

  if (style === "mini") {
    return {
      dx1: 94 + d * 16,
      dx2: 126 + d * 22,
      dy1: 58 + d * 10,
      dy2: 78 + d * 14
    };
  }

  if (style === "calm") {
    return {
      dx1: 70 + d * 8,
      dx2: 94 + d * 12,
      dy1: 50 + d * 7,
      dy2: 64 + d * 9
    };
  }

  return {
    dx1: 92 + d * 12,
    dx2: 122 + d * 18,
    dy1: 54 + d * 8,
    dy2: 74 + d * 12
  };
}

function platformSize(style) {
  const r = Math.random();
  const d = difficulty();
  let rx, ry;

  if (score < 5) {
    rx = r < 0.2 ? 58 : r < 0.8 ? 68 : 76;
    ry = r < 0.2 ? 26 : r < 0.8 ? 31 : 35;
  } else if (score < 12) {
    rx = r < 0.28 ? 52 : r < 0.82 ? 62 : 70;
    ry = r < 0.28 ? 24 : r < 0.82 ? 29 : 33;
  } else if (score < 22) {
    rx = r < 0.34 ? 46 : r < 0.84 ? 56 : 66;
    ry = r < 0.34 ? 22 : r < 0.84 ? 27 : 31;
  } else {
    rx = r < 0.42 ? 42 : r < 0.86 ? 52 : 60;
    ry = r < 0.42 ? 20 : r < 0.86 ? 25 : 29;
  }

  if (style === "long") { rx += 3; ry += 1; }
  if (style === "mini") { rx -= 8 + d * 3; ry -= 3 + d * 1.5; }
  if (style === "calm") rx += 2;

  return { rx: clamp(rx, 38, 78), ry: clamp(ry, 18, 36) };
}

function validPlatform(c) {
  const recent = platforms.slice(-4);
  for (const p of recent) {
    const dx = Math.abs(c.x - p.x);
    const dy = Math.abs(c.y - p.y);
    if (dx < (c.rx + p.rx) * .88 && dy < 82) return false;
    if (Math.hypot(dx * .95, dy * 1.18) < 118) return false;
  }
  return true;
}

function addPlatform() {
  const last = platforms[platforms.length - 1];
  const style = chooseStyle();
  let chosen = null;
  let chosenDir = routeDir;
  for (let i = 0; i < 18; i++) {
    let dir = chooseDir(last, style);
    if (i > 7) dir = Math.random() > 0.5 ? 1 : -1;
    const r = rangeByStyle(style);
    let x = last.x + dir * random(r.dx1, r.dx2);
    if (x < SAFE_LEFT || x > W - SAFE_RIGHT) {
      dir *= -1;
      x = last.x + dir * random(r.dx1, r.dx2);
    }
    x = clamp(x, SAFE_LEFT, W - SAFE_RIGHT);
    const y = last.y - random(r.dy1, r.dy2);
    const s = platformSize(style);
    const types = ["butterfly", "wisteria", "moon", "obsidian", "shrine"];
    const c = makePlatform(x, y, s.rx, s.ry, types[Math.floor(Math.random()*types.length)]);
    if (validPlatform(c)) { chosen = c; chosenDir = dir; break; }
  }
  if (!chosen) {
    chosenDir = routeDir * -1;
    chosen = makePlatform(clamp(last.x + chosenDir * 118, SAFE_LEFT, W - SAFE_RIGHT), last.y - 68, 58, 28, "butterfly");
  }
  if (chosenDir === routeDir) routeStreak++;
  else { routeDir = chosenDir; routeStreak = 1; }
  platforms.push(chosen);
}

function recenterWorld() {
  const dx = BASE.x - currentPlatform.x;
  const dy = BASE.y - currentPlatform.y;
  [...platforms, ...particles, ...rings, ...butterflies, ...slashes, ...afterImages].forEach(o => { o.x += dx; o.y += dy; });
  player.x += dx;
  player.y += dy;
}

function draw() {
  ctx.clearRect(0,0,W,H);
  const sx = cameraShake ? random(-cameraShake/2, cameraShake/2) : 0;
  const sy = cameraShake ? random(-cameraShake/2, cameraShake/2) : 0;
  ctx.save();
  ctx.translate(sx, sy);
  drawBackground();
  drawPlatforms();
  drawRings();
  drawAfterImages();
  drawSlashes();
  drawPlayer();
  drawParticles();
  drawButterflies();
  drawPower();
  ctx.restore();

  // V7：最终边缘遮罩。
  // 有些精灵图在镜像/残影时会把素材边缘露在画面左右侧，
  // 这里在 canvas 最后盖一层和背景一致的软遮罩，彻底挡住左右素材条。
  drawEdgeCovers();

  if (flash > 0) {
    ctx.fillStyle = `rgba(255,225,255,${flash})`;
    ctx.fillRect(0,0,W,H);
    flash *= 0.82;
  }
  cameraShake *= 0.82;
  if (cameraShake < .1) cameraShake = 0;
}

function drawEdgeCovers() {
  const coverW = 34;

  ctx.save();

  const left = ctx.createLinearGradient(0, 0, coverW, 0);
  left.addColorStop(0, "rgba(18, 7, 31, 1)");
  left.addColorStop(0.55, "rgba(18, 7, 31, 0.98)");
  left.addColorStop(1, "rgba(18, 7, 31, 0)");
  ctx.fillStyle = left;
  ctx.fillRect(0, 0, coverW, H);

  const right = ctx.createLinearGradient(W - coverW, 0, W, 0);
  right.addColorStop(0, "rgba(18, 7, 31, 0)");
  right.addColorStop(0.45, "rgba(18, 7, 31, 0.98)");
  right.addColorStop(1, "rgba(18, 7, 31, 1)");
  ctx.fillStyle = right;
  ctx.fillRect(W - coverW, 0, coverW, H);

  ctx.restore();
}

function drawBackground() {
  const t = performance.now() * 0.001;
  const g = ctx.createLinearGradient(0,0,0,H);
  g.addColorStop(0,"#251036");
  g.addColorStop(.5,"#170822");
  g.addColorStop(1,"#09030e");
  ctx.fillStyle = g;
  ctx.fillRect(0,0,W,H);

  const cx = W/2, cy = 205 + Math.sin(t*.7)*5;
  const vortex = ctx.createRadialGradient(cx,cy,20,cx,cy,128);
  vortex.addColorStop(0,"rgba(18,10,34,.86)");
  vortex.addColorStop(.35,"rgba(62,34,98,.62)");
  vortex.addColorStop(.58,"rgba(142,82,210,.38)");
  vortex.addColorStop(.84,"rgba(198,122,255,.14)");
  vortex.addColorStop(1,"rgba(198,122,255,0)");
  ctx.fillStyle = vortex;
  ctx.beginPath(); ctx.arc(cx,cy,128,0,Math.PI*2); ctx.fill();
  ctx.globalAlpha = .18;
  ctx.strokeStyle = "rgba(255,220,255,.3)";
  for (let i=0;i<4;i++) { ctx.beginPath(); ctx.arc(cx,cy,36+i*22,0.2,Math.PI*1.35); ctx.stroke(); }
  ctx.globalAlpha = 1;

  motes.forEach(m => {
    m.y += m.speed; m.x += Math.sin(t + m.y*.02)*m.drift;
    if (m.y > H+10) { m.y=-10; m.x=Math.random()*W; }
    ctx.fillStyle = `rgba(245,205,255,${m.a})`;
    ctx.shadowColor = "rgba(220,150,255,.7)"; ctx.shadowBlur = 8;
    ctx.beginPath(); ctx.arc(m.x,m.y,m.r,0,Math.PI*2); ctx.fill();
    ctx.shadowBlur = 0;
  });

  bgButterflies.forEach(b => {
    b.y += b.speed; b.x += Math.sin(t*1.6 + b.phase)*.45;
    if (b.y > H+20) { b.y=-20; b.x=Math.random()*W; }
    drawButterfly(b.x,b.y,b.s,`rgba(245,210,255,${b.alpha})`,Math.sin(t+b.phase)*.35,true);
  });
}

function drawPlatforms() {
  [...platforms].sort((a,b)=>a.y-b.y).forEach(p => {
    const index = platforms.indexOf(p);
    if (p.y < SAFE_TOP || p.y > H + 120) return;
    let alpha = 1;
    if (index > 4) alpha = .52; else if (index > 2) alpha = .76;
    if (p.y < SAFE_TOP+55) alpha *= clamp((p.y - SAFE_TOP)/55,0,1);
    ctx.save(); ctx.globalAlpha = alpha; drawPlatform(p); ctx.restore();
  });
}

function platformY(p) {
  if (p === currentPlatform) return p.y + p.press;
  return p.y + p.press + Math.sin(performance.now()*0.00115 + p.seed) * 2.1;
}

function theme(type) {
  const T = {
    main:["#fff4ff","#dfa4ff","#965fe5","#6e3fc0","#32194e","#1a0b2a","#5e3190","#32184f"],
    butterfly:["#fff0ff","#d893ff","#8f55de","#7040bd","#2d1646","#160922","#5b2c86","#2c1447"],
    wisteria:["#fff0fb","#dba2ed","#935cbf","#68418f","#2b153c","#16091e","#603267","#31173a"],
    moon:["#f3f0ff","#b7b1f4","#6c68c8","#4a47a1","#191a38","#0e0e21","#3a3b74","#1d1e3e"],
    obsidian:["#d9c7ff","#8d6de0","#433075","#23133f","#160a26","#0d0618","#342052","#1a0c2a"],
    shrine:["#ffe4f8","#d177b8","#85416f","#5a284e","#25101e","#120811","#4f233e","#25101d"]
  };
  return T[type] || T.main;
}

function drawPlatform(p) {
  const x=p.x, y=platformY(p), rx=p.rx, ry=p.ry, h=p.h;
  const c = theme(p.type);
  const pulse = .55 + Math.sin(performance.now()*0.002 + p.pulse)*.25;
  ctx.save();
  const glow = ctx.createRadialGradient(x,y+16,10,x,y+16,rx*1.65);
  glow.addColorStop(0,`rgba(255,160,235,${.13+pulse*.08})`);
  glow.addColorStop(.45,`rgba(170,105,255,${.08+pulse*.05})`);
  glow.addColorStop(1,"rgba(170,105,255,0)");
  ctx.fillStyle=glow; ctx.beginPath(); ctx.ellipse(x,y+20,rx*1.7,ry*1.6,0,0,Math.PI*2); ctx.fill();
  ctx.shadowColor = p.glow ? `rgba(255,142,232,${.75+pulse*.25})` : `rgba(180,105,255,${.55+pulse*.18})`;
  ctx.shadowBlur = p.glow ? 30 : 20;

  const left=ctx.createLinearGradient(x-rx,y,x,y+ry+h);
  left.addColorStop(0,c[4]); left.addColorStop(.65,c[5]); left.addColorStop(1,"#07020b");
  ctx.fillStyle=left; ctx.beginPath(); ctx.moveTo(x-rx,y); ctx.lineTo(x,y+ry); ctx.lineTo(x,y+ry+h); ctx.lineTo(x-rx,y+h); ctx.closePath(); ctx.fill();
  const right=ctx.createLinearGradient(x,y,x+rx,y+ry+h);
  right.addColorStop(0,c[6]); right.addColorStop(.65,c[7]); right.addColorStop(1,"#100519");
  ctx.fillStyle=right; ctx.beginPath(); ctx.moveTo(x+rx,y); ctx.lineTo(x,y+ry); ctx.lineTo(x,y+ry+h); ctx.lineTo(x+rx,y+h); ctx.closePath(); ctx.fill();
  const top=ctx.createLinearGradient(x,y-ry,x,y+ry);
  top.addColorStop(0,c[0]); top.addColorStop(.38,c[1]); top.addColorStop(.75,c[2]); top.addColorStop(1,c[3]);
  ctx.fillStyle=top; ctx.beginPath(); ctx.moveTo(x,y-ry); ctx.lineTo(x+rx,y); ctx.lineTo(x,y+ry); ctx.lineTo(x-rx,y); ctx.closePath(); ctx.fill();
  const shine=ctx.createLinearGradient(x-rx,y-ry,x+rx,y+ry);
  shine.addColorStop(0,"rgba(255,255,255,.28)"); shine.addColorStop(.3,"rgba(255,255,255,.03)"); shine.addColorStop(1,"rgba(255,255,255,.16)");
  ctx.fillStyle=shine; ctx.beginPath(); ctx.moveTo(x,y-ry); ctx.lineTo(x+rx,y); ctx.lineTo(x,y+ry); ctx.lineTo(x-rx,y); ctx.closePath(); ctx.fill();
  ctx.shadowBlur=0;
  ctx.strokeStyle="rgba(255,245,255,.38)"; ctx.lineWidth=1.45;
  ctx.beginPath(); ctx.moveTo(x,y-ry); ctx.lineTo(x+rx,y); ctx.lineTo(x,y+ry); ctx.lineTo(x-rx,y); ctx.closePath(); ctx.stroke();
  ctx.strokeStyle="rgba(20,8,32,.58)"; ctx.lineWidth=2.2; ctx.beginPath(); ctx.moveTo(x-rx,y); ctx.lineTo(x,y+ry); ctx.lineTo(x+rx,y); ctx.stroke();
  ctx.strokeStyle="rgba(255,255,255,.12)"; ctx.lineWidth=1;
  for(let i=-rx+14;i<rx-8;i+=16){ctx.beginPath();ctx.moveTo(x+i,y-ry);ctx.lineTo(x+i+38,y+ry);ctx.stroke();}
  drawButterfly(x+8,y-5,.34,"rgba(255,255,255,.62)",Math.sin(performance.now()*0.001+p.seed)*.2,true);
  ctx.restore();
  p.press *= .8; if (Math.abs(p.press)<.05) p.press=0;
}

function drawPlayer() {
  if (!player) return;
  const x = player.x;
  const y = player.y;
  ctx.save();
  ctx.globalAlpha = .28 * player.shadow;
  ctx.fillStyle = "#000";
  ctx.beginPath(); ctx.ellipse(x,y+8,26,7,0,0,Math.PI*2); ctx.fill();
  ctx.globalAlpha = 1;

  let state = spriteState();
  const cfg = spriteConfig[state];
  const img = sprites[state];
  if (player.prevState !== state) { player.frameT = 0; player.prevState = state; }
  player.frameT += 0.05;

  const bob = state === "idle" ? Math.sin(performance.now()*0.004)*2 : 0;
  const breathe = state === "idle" ? 1 + Math.sin(performance.now()*0.004)*0.018 : 1;
  const chargeSquash = state === "charge" ? 1 - power * 0.0011 : 1;
  const sx = player.dir * player.scaleX * breathe;
  const sy = player.scaleY * chargeSquash;

  if (state === "charge") drawChargeCircle(x, y - 48);

  if (img && img.complete && img.naturalWidth > 0) {
    const dh = cfg.h;
    const dw = dh * img.naturalWidth / img.naturalHeight;
    ctx.save();
    ctx.translate(x + cfg.x, y + cfg.y + bob);
    ctx.rotate(player.angle);
    ctx.scale(sx, sy);
    ctx.shadowColor = "rgba(225,155,255,.85)";
    ctx.shadowBlur = state === "jump" ? 22 : 14;
    ctx.drawImage(img, -dw/2, -dh, dw, dh);
    ctx.restore();
  } else {
    drawFallbackHero(x, y, state, sx, sy);
  }
}

function drawFallbackHero(x, y, state, sx, sy) {
  // 极端情况下图片还没加载出来，也不会“人物消失”。
  ctx.save();
  ctx.translate(x, y);
  ctx.scale(sx, sy);
  const jumpLift = state === "jump" ? -6 : 0;

  ctx.shadowColor = "rgba(225,155,255,.85)";
  ctx.shadowBlur = 16;

  // 翅膀
  const wing = ctx.createLinearGradient(-30, -80, 30, -20);
  wing.addColorStop(0, "#ffffff");
  wing.addColorStop(.55, "#f0e7ff");
  wing.addColorStop(1, "#ffcff1");
  ctx.fillStyle = wing;
  ctx.beginPath();
  ctx.ellipse(-20, -44 + jumpLift, 17, 31, -0.35, 0, Math.PI * 2);
  ctx.ellipse(20, -44 + jumpLift, 17, 31, 0.35, 0, Math.PI * 2);
  ctx.fill();

  // 身体
  ctx.fillStyle = "#150d22";
  roundRect(-13, -58 + jumpLift, 26, 42, 10);
  ctx.fill();
  ctx.fillStyle = "#f4efff";
  ctx.beginPath();
  ctx.moveTo(-10, -29 + jumpLift);
  ctx.lineTo(0, -16 + jumpLift);
  ctx.lineTo(10, -29 + jumpLift);
  ctx.closePath();
  ctx.fill();

  // 头
  ctx.fillStyle = "#f2cfc8";
  ctx.beginPath();
  ctx.arc(0, -78 + jumpLift, 17, 0, Math.PI * 2);
  ctx.fill();
  ctx.fillStyle = "#11101b";
  ctx.beginPath();
  ctx.arc(0, -85 + jumpLift, 19, Math.PI, Math.PI * 2);
  ctx.fill();
  ctx.beginPath();
  ctx.ellipse(-10, -76 + jumpLift, 7, 16, .18, 0, Math.PI * 2);
  ctx.ellipse(10, -76 + jumpLift, 7, 16, -.18, 0, Math.PI * 2);
  ctx.fill();

  ctx.fillStyle = "#3f285f";
  ctx.beginPath();
  ctx.arc(-6, -78 + jumpLift, 2.5, 0, Math.PI * 2);
  ctx.arc(6, -78 + jumpLift, 2.5, 0, Math.PI * 2);
  ctx.fill();
  drawButterfly(0, -101 + jumpLift, 1.05, "rgba(228,186,255,.98)", 0, true);

  ctx.restore();
}

function spriteState() {
  if (!player) return "idle";
  if (player.state === "charging") return "charge";
  if (player.state === "jumping") return "jump";
  if (player.state === "falling") return "fall";
  if (player.state === "land") return "land";
  return "idle";
}

function faceNextPlatform() {
  if (!player || !targetPlatform) return;
  if (player.state === "jumping" || player.state === "falling") return;
  player.dir = targetPlatform.x >= player.x ? 1 : -1;
}

function drawChargeCircle(x,y) {
  const t = performance.now()*0.006;
  const r = 34 + power*.28;
  ctx.save();
  const aura=ctx.createRadialGradient(x,y,4,x,y,82);
  aura.addColorStop(0,`rgba(255,160,235,${.18+power/320})`);
  aura.addColorStop(.48,"rgba(170,105,255,.12)"); aura.addColorStop(1,"rgba(170,105,255,0)");
  ctx.fillStyle=aura; ctx.beginPath(); ctx.arc(x,y,82,0,Math.PI*2); ctx.fill();
  ctx.strokeStyle=`rgba(255,185,245,${.24+power/400})`; ctx.lineWidth=1.7; ctx.shadowColor="rgba(220,140,255,.8)"; ctx.shadowBlur=14;
  for(let i=0;i<2;i++){ctx.beginPath();ctx.arc(x,y,r+i*10,t+i,t+Math.PI*1.35+i);ctx.stroke();}
  for(let i=0;i<7;i++){const a=t*1.3+i*Math.PI*2/7;drawButterfly(x+Math.cos(a)*(r+5), y+Math.sin(a)*(r*.55), .26+power/900, "rgba(255,205,250,.62)", a, true);}
  ctx.restore();
}

function update() {
  updateEffects();
  if (gameState !== "playing" || !player) return;

  faceNextPlatform();

  if (charging && player.state !== "jumping" && player.state !== "falling") {
    power += 1.12;
    power = Math.min(power,100);
    player.state = "charging";
    player.scaleX += (1.06 - player.scaleX)*.22;
    player.scaleY += (.92 - player.scaleY)*.22;
    currentPlatform.press += (8-currentPlatform.press)*.2;
    if (Math.random()<.18) spawnButterfly(player.x+random(-32,32), player.y-55+random(-18,18), random(-.5,.5), random(-.8,-.2), random(.22,.38));
  }

  if (!charging && player.state !== "jumping" && player.state !== "falling") {
    player.scaleX += (1-player.scaleX)*.22;
    player.scaleY += (1-player.scaleY)*.22;
    player.angle += (0-player.angle)*.18;
    if (player.state === "land") {
      player.landTimer--;
      if (player.landTimer <= 0) player.state = "idle";
    } else {
      player.state = "idle";
    }
  }

  if (player.state === "falling") {
    player.y += player.vy;
    player.vy += .42;
    player.angle += .06 * player.dir;
    player.shadow *= .95;
    if (Math.random()<.22) spawnButterfly(player.x+random(-16,16), player.y-58, random(-1,1), random(-1.2,.2), random(.22,.36));
    if (player.y > H+120) die();
  }

  if (jump) updateJump();
}

function updateEffects() {
  particles = particles.filter(p=>p.life>0);
  rings = rings.filter(r=>r.life>0);
  butterflies = butterflies.filter(b=>b.life>0);
  slashes = slashes.filter(s=>s.life>0);
  afterImages = afterImages.filter(a=>a.life>0);
}

function beginJump() {
  initAudio();
  if (gameState !== "playing" || !player || !currentPlatform || !targetPlatform) return;
  if (player.state === "jumping" || player.state === "falling") return;
  const startX = player.x;
  const startY = player.y;
  const dx = targetPlatform.x - startX;
  const dy = (targetPlatform.y - 8) - startY;
  const dist = Math.hypot(dx,dy);
  const ux = dx/dist, uy = dy/dist;
  const jumpDistance = 40 + power * (1.86 + difficulty() * 0.06);
  const endX = startX + ux*jumpDistance;
  const endY = startY + uy*jumpDistance;
  player.state = "jumping";
  player.dir = dx >= 0 ? 1 : -1;
  currentPlatform.press = -8;
  cameraShake = 4;
  flash = .05;
  playSound("jump");
  spawnTakeoff(startX,currentPlatform.y+6);
  spawnSlash(startX,startY-58,player.dir);
  jump = { startX,startY,endX,endY,startTime:performance.now(),duration:500+power*2,arc:76+power*.64,lastTrail:0 };
  power = 0;
}

function updateJump() {
  const now = performance.now();
  const t = Math.min((now - jump.startTime)/jump.duration, 1);
  const e = ease(t);
  player.x = lerp(jump.startX,jump.endX,e);
  player.y = lerp(jump.startY,jump.endY,e) - Math.sin(Math.PI*t)*jump.arc;
  player.scaleX = 1 + Math.sin(Math.PI*t)*.05;
  player.scaleY = 1 - Math.sin(Math.PI*t)*.03;
  player.angle = Math.sin(t*Math.PI*2)*.04;
  player.shadow = 1 - Math.sin(Math.PI*t)*.58;
  if (Math.random()<.38) spawnButterfly(player.x-player.dir*random(18,30), player.y-random(55,80), -player.dir*random(.6,1.3), random(-.7,-.2), random(.24,.42));
  if (now - jump.lastTrail > 80) { jump.lastTrail = now; spawnAfterImage(player.x,player.y,player.dir,player.angle); }
  if (t>=1) finishJump();
}

function finishJump() {
  const landed = isLanding(player.x, player.y, targetPlatform);
  jump = null;
  player.angle = 0;
  player.shadow = 1;
  if (!landed) { startFalling(); return; }
  const landedOffsetX = clamp(player.x - targetPlatform.x, -targetPlatform.rx*.4, targetPlatform.rx*.4);
  currentPlatform = targetPlatform;
  platforms.shift();
  currentPlatform = platforms[0];
  recenterWorld();
  player.offsetXOnPlatform = landedOffsetX;
  player.x = currentPlatform.x + landedOffsetX;
  player.y = currentPlatform.y - 8;
  player.state = "land";
  player.landTimer = 14;
  player.scaleX = 1.08;
  player.scaleY = .94;
  player.vy = 0;
  currentPlatform.press = 13;
  score++;
  updateScore();
  cameraShake = 5;
  flash = .06;
  playSound("land");
  spawnLanding(player.x,currentPlatform.y+6);
  while (platforms.length < PLATFORM_COUNT) addPlatform();
  targetPlatform = platforms[1];
  faceNextPlatform();
}

function isLanding(x,y,p) {
  const dx = Math.abs(x-p.x);
  const dy = Math.abs(y-(p.y-8));
  const d = difficulty();
  const xTolerance = 0.78 - d * 0.14;
  const yTolerance = 0.94 - d * 0.16;
  return dx/(p.rx*xTolerance) + dy/(p.ry*yTolerance) <= 1;
}

function startFalling() {
  playSound("fall");
  player.state = "falling";
  player.vy = 4.2;
  player.shadow = .4;
  cameraShake = 3;
  for(let i=0;i<10;i++) spawnParticle(player.x,player.y-45,i%2?"rgba(255,160,230,.58)":"rgba(185,145,255,.52)",1.5);
}

function die() {
  gameState = "dead";
  charging = false;
  power = 0;
  jump = null;
  cameraShake = 8;
  show(deadScreen);
}

function spawnTakeoff(x,y) {
  spawnRing(x,y,18,7,"rgba(255,185,245,.55)",2.1,.03,4);
  spawnRing(x,y,25,9,"rgba(205,165,255,.45)",1.8,.028,5);
  for(let i=0;i<14;i++) spawnParticle(x,y-10,i%2?"rgba(255,165,235,.82)":"rgba(200,155,255,.75)",2.4);
  for(let i=0;i<10;i++) spawnButterfly(x+random(-36,36),y-25+random(-18,18),random(-1.8,1.8),-Math.random()*1.3,random(.25,.4));
}

function spawnLanding(x,y) {
  spawnRing(x,y,22,8,"rgba(255,220,255,.82)",2.5,.026,7);
  spawnRing(x,y,36,13,"rgba(255,160,235,.58)",2.25,.024,9);
  for(let i=0;i<20;i++) spawnParticle(x,y-10,i%2?"rgba(255,180,240,.82)":"rgba(210,170,255,.74)",2.6);
  for(let i=0;i<12;i++) spawnButterfly(x+random(-54,54),y-20+random(-22,18),random(-2,2),-Math.random()*1.1,random(.24,.42));
}

function spawnParticle(x,y,color,force) {
  particles.push({x,y,vx:random(-force/2,force/2),vy:-Math.random()*force-.25,size:Math.random()*3+2,life:Math.random()*.35+.45,rot:Math.random()*Math.PI,color});
}

function drawParticles() {
  particles.forEach(p=>{
    ctx.save(); ctx.globalAlpha=p.life; ctx.fillStyle=p.color; ctx.shadowColor=p.color; ctx.shadowBlur=8;
    ctx.beginPath(); ctx.ellipse(p.x,p.y,p.size,p.size*1.6,p.rot,0,Math.PI*2); ctx.fill(); ctx.restore();
    p.x+=p.vx; p.y+=p.vy; p.vy+=.03; p.rot+=.08; p.life-=.018;
  });
}

function spawnRing(x,y,rx,ry,color,speed,fade,butterfliesCount) {
  rings.push({x,y,rx,ry,color,speed,fade,butterflies:butterfliesCount,width:2,life:.88,spin:Math.random()*Math.PI*2});
}

function drawRings() {
  rings.forEach(r=>{
    ctx.save(); ctx.globalAlpha=r.life; ctx.strokeStyle=r.color; ctx.lineWidth=r.width; ctx.shadowColor=r.color; ctx.shadowBlur=14;
    ctx.beginPath(); ctx.ellipse(r.x,r.y,r.rx,r.ry,0,0,Math.PI*2); ctx.stroke();
    for(let i=0;i<r.butterflies;i++){const a=Math.PI*2/r.butterflies*i+r.spin; drawButterfly(r.x+Math.cos(a)*r.rx,r.y+Math.sin(a)*r.ry,.22,`rgba(255,210,255,${r.life*.75})`,a,false);}
    ctx.restore(); r.rx+=r.speed; r.ry+=r.speed*.36; r.life-=r.fade; r.spin+=.025;
  });
}

function spawnButterfly(x,y,vx,vy,s) {
  butterflies.push({x,y,vx,vy,s,color:Math.random()>.45?"rgba(255,205,250,.72)":"rgba(190,160,255,.68)",rot:Math.random()*Math.PI*2,spin:random(-.08,.08),life:.75+Math.random()*.25});
}

function drawButterflies() {
  butterflies.forEach(b=>{
    ctx.save(); ctx.globalAlpha=b.life; drawButterfly(b.x,b.y,b.s,b.color,b.rot,true); ctx.restore();
    b.x+=b.vx; b.y+=b.vy; b.vy+=.02; b.rot+=b.spin; b.life-=.018;
  });
}

function drawButterfly(x,y,s,color,rot=0,glow=false) {
  ctx.save(); ctx.translate(x,y); ctx.rotate(rot); ctx.scale(s,s);
  if(glow){ctx.shadowColor="rgba(230,170,255,.75)"; ctx.shadowBlur=10;}
  ctx.fillStyle=color; ctx.beginPath();
  ctx.ellipse(-5,0,5,8,-.55,0,Math.PI*2); ctx.ellipse(5,0,5,8,.55,0,Math.PI*2); ctx.ellipse(-4,6,4,5,.45,0,Math.PI*2); ctx.ellipse(4,6,4,5,-.45,0,Math.PI*2); ctx.fill();
  ctx.fillStyle="rgba(255,255,255,.66)"; ctx.fillRect(-1,-2,2,10); ctx.restore();
}

function spawnSlash(x,y,dir){slashes.push({x,y,dir,r:20,life:.55});}
function drawSlashes(){slashes.forEach(s=>{ctx.save();ctx.globalAlpha=s.life;ctx.translate(s.x,s.y);ctx.scale(s.dir,1);ctx.strokeStyle=`rgba(255,220,255,${s.life})`;ctx.lineWidth=4;ctx.shadowColor="rgba(255,150,240,.9)";ctx.shadowBlur=16;ctx.beginPath();ctx.arc(0,0,s.r,-.9,.65);ctx.stroke();ctx.restore();s.r+=2.4;s.life-=.035;});}

function spawnAfterImage(x,y,dir,angle){afterImages.push({x,y,dir,angle,life:.22,state:spriteState()});}
function drawAfterImages(){
  afterImages.forEach(a=>{
    // V7：残影不再直接绘制整张人物图，避免边缘素材被拖到屏幕左右两侧。
    ctx.save();
    ctx.globalAlpha = a.life;
    ctx.translate(a.x, a.y - 58);
    ctx.rotate(a.angle);
    ctx.scale(a.dir, 1);
    ctx.fillStyle = "rgba(210,150,255,0.20)";
    ctx.shadowColor = "rgba(210,150,255,0.9)";
    ctx.shadowBlur = 18;
    ctx.beginPath();
    ctx.ellipse(0, 0, 26, 44, -0.18, 0, Math.PI * 2);
    ctx.fill();
    ctx.restore();
    a.life -= .035;
  });
}

function drawPower() {
  if (gameState !== "playing" || !charging || !player || player.state === "jumping" || player.state === "falling") return;
  const x=62,y=650,w=266,h=14;
  ctx.save(); ctx.fillStyle="rgba(255,255,255,.12)"; roundRect(x,y,w,h,999); ctx.fill();
  const g=ctx.createLinearGradient(x,y,x+w,y); g.addColorStop(0,"#8668ff"); g.addColorStop(.45,"#c777ff"); g.addColorStop(1,"#ff8fda");
  ctx.fillStyle=g; roundRect(x,y,w*(power/100),h,999); ctx.fill();
  ctx.strokeStyle="rgba(255,255,255,.28)"; ctx.lineWidth=1; roundRect(x,y,w,h,999); ctx.stroke(); ctx.restore();
}

function roundRect(x,y,w,h,r){if(ctx.roundRect){ctx.beginPath();ctx.roundRect(x,y,w,h,r);return;}ctx.beginPath();ctx.moveTo(x+r,y);ctx.lineTo(x+w-r,y);ctx.quadraticCurveTo(x+w,y,x+w,y+r);ctx.lineTo(x+w,y+h-r);ctx.quadraticCurveTo(x+w,y+h,x+w-r,y+h);ctx.lineTo(x+r,y+h);ctx.quadraticCurveTo(x,y+h,x,y+h-r);ctx.lineTo(x,y+r);ctx.quadraticCurveTo(x,y,x+r,y);}

function gameLoop(){draw();update();requestAnimationFrame(gameLoop);}

function startChargeInput(e) {
  if (e) e.preventDefault();
  if (gameState === "playing" && player && player.state !== "jumping" && player.state !== "falling") {
    initAudio();
    if (!charging) playSound("charge");
    charging = true;
  }
}

function endChargeInput(e) {
  if (e) e.preventDefault();
  if (charging) {
    charging = false;
    beginJump();
  }
}

if (window.PointerEvent) {
  canvas.addEventListener("pointerdown", e => {
    startChargeInput(e);
    try { canvas.setPointerCapture(e.pointerId); } catch (_) {}
  }, { passive: false });
  canvas.addEventListener("pointerup", endChargeInput, { passive: false });
  canvas.addEventListener("pointercancel", endChargeInput, { passive: false });
  window.addEventListener("pointerup", endChargeInput, { passive: false });
} else {
  canvas.addEventListener("touchstart", startChargeInput, { passive: false });
  canvas.addEventListener("touchend", endChargeInput, { passive: false });
  canvas.addEventListener("touchcancel", endChargeInput, { passive: false });
  canvas.addEventListener("mousedown", startChargeInput);
  window.addEventListener("mouseup", endChargeInput);
}

if (startBtn) startBtn.onclick = startGame;
if (reviveBtn) reviveBtn.onclick = revive;
if (restartBtn) restartBtn.onclick = restart;
window.startGame = startGame;
window.revive = revive;
window.restart = restart;

setupCanvas();
window.addEventListener("resize", setupCanvas);
gameLoop();
